public static void main(Args _args)
{
    ETGCustAgingMMRController controller = new ETGCustAgingMMRController();


    if (curExt() == "o025")
    {
        controller.parmReportName(ssrsReportStr(ETGCustAgingMMR, PrecisionDesign3));
    }
    else
    {
        controller.parmReportName(ssrsReportStr(ETGCustAgingMMR, PrecisionDesign1));
    }

    controller.parmArgs(_args);
    controller.parmDialogCaption("Customer Aging MMR");
    controller.startOperation();
}

protected void prePromptModifyContract()
{
    super();

    ETGCustAgingMMRContract contract = this.parmReportContract().parmRdpContract() as ETGCustAgingMMRContract;

    if (curExt() == "o025")
    {
        if (contract.parmReportType() == ETGReportType::Summary)
        {
            this.parmReportName(ssrsReportStr(ETGCustAgingMMR, PrecisionDesign4));
            this.parmReportContract().parmReportName(ssrsReportStr(ETGCustAgingMMR, PrecisionDesign4));
        }
        else
        {
            this.parmReportName(ssrsReportStr(ETGCustAgingMMR, PrecisionDesign3));
            this.parmReportContract().parmReportName(ssrsReportStr(ETGCustAgingMMR, PrecisionDesign3));
        }
    }
    else
    {
        if (contract.parmReportType() == ETGReportType::Summary)
        {
            this.parmReportName(ssrsReportStr(ETGCustAgingMMR, PrecisionDesign2));
            this.parmReportContract().parmReportName(ssrsReportStr(ETGCustAgingMMR, PrecisionDesign2));
        }
        else
        {
            this.parmReportName(ssrsReportStr(ETGCustAgingMMR, PrecisionDesign1));
            this.parmReportContract().parmReportName(ssrsReportStr(ETGCustAgingMMR, PrecisionDesign1));
        }
    }
}

